import type { ParsedRawEntry } from '../jsonl'
import { asArray, getBoolean, getString, isRecord, type JsonRecord } from '../utils'

export type RawContentBlock = JsonRecord

const unwrapRaw = (entry: ParsedRawEntry | JsonRecord): JsonRecord => {
  if ('raw' in entry && isRecord(entry.raw)) {
    return entry.raw
  }

  return entry
}

export const getEntryType = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).type)

export const getEntryUuid = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).uuid)

export const getEntryParentUuid = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).parentUuid)

export const getEntryTimestamp = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).timestamp)

export const isSidechainEntry = (entry: ParsedRawEntry | JsonRecord): boolean =>
  getBoolean(unwrapRaw(entry).isSidechain) ?? false

export const getMessage = (
  entry: ParsedRawEntry | JsonRecord,
): JsonRecord | undefined => {
  const raw = unwrapRaw(entry)
  return isRecord(raw.message) ? raw.message : undefined
}

export const getMessageModel = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(getMessage(entry)?.model)

export const getMessageUsage = (
  entry: ParsedRawEntry | JsonRecord,
): JsonRecord | undefined => {
  const usage = getMessage(entry)?.usage
  return isRecord(usage) ? usage : undefined
}

export const getPermissionMode = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).permissionMode)

export const getSlug = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).slug)

export const getCwd = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).cwd)

export const getGitBranch = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).gitBranch)

export const getTopLevelToolUseResult = (
  entry: ParsedRawEntry | JsonRecord,
): unknown => unwrapRaw(entry).toolUseResult

export const getMessageContent = (entry: ParsedRawEntry | JsonRecord): unknown =>
  getMessage(entry)?.content

export const getContentBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  asArray<unknown>(getMessageContent(entry)).filter(isRecord)

export const getTextBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'text')

export const getToolUseBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'tool_use')

export const getToolResultBlocks = (
  entry: ParsedRawEntry | JsonRecord,
): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'tool_result')

export const extractTextContent = (content: unknown): string | undefined => {
  if (typeof content === 'string') {
    return content
  }

  const parts = asArray<unknown>(content)
    .map(part => {
      if (typeof part === 'string') return part
      if (!isRecord(part)) return undefined

      if (getString(part.type) === 'text') {
        return getString(part.text)
      }

      if (getString(part.type) === 'tool_reference') {
        const toolName = getString(part.tool_name)
        return toolName ? `tool:${toolName}` : undefined
      }

      return JSON.stringify(part)
    })
    .filter((part): part is string => Boolean(part))

  return parts.length > 0 ? parts.join('\n\n') : undefined
}

export const extractPersistedOutputPath = (text: string): string | undefined => {
  const match = text.match(/Full output saved to:\s+(.+?)(?:\n|$)/)
  return match?.[1]?.trim()
}

import type {
  AgentThread,
  CanonicalEvent,
  CanonicalSession,
  HookEvent,
  SessionArtifact,
  ToolCallEvent,
  ToolResultEvent,
} from '@howicc/canonical'
import type { OpenRouterCatalog } from '@howicc/model-pricing'
import type { DiscoveredSession, SourceBundle } from '@howicc/parser-core'
import { parseJsonlFile } from '../jsonl'
import { buildAssetRefs } from '../parse/buildAssetRefs'
import { buildEvents } from '../parse/buildEvents'
import { buildSessionMetadata } from '../parse/metadata'
import { buildClaudeCodeMetrics } from '../parse/metrics'
import { selectActiveThread } from '../parse/selectActiveThread'
import { extractPlanArtifacts, extractQuestionArtifacts, extractTodoArtifacts, extractToolDecisionArtifacts, extractToolOutputArtifacts } from '../extractors'
import { buildSearchText } from './buildSearchText'

export const buildClaudeCanonicalSession = async (input: {
  bundle: SourceBundle
  session: DiscoveredSession
  parserVersion: string
  pricingCatalog?: OpenRouterCatalog
}): Promise<CanonicalSession> => {
  const rawEntries = await parseJsonlFile(input.bundle.manifest.transcript.absolutePath)
  const selection = selectActiveThread(rawEntries)
  const assets = await buildAssetRefs(input.bundle)
  const assetIdByAbsolutePath = new Map(
    assets
      .map(asset => {
        const absolutePath = asset.providerData?.absolutePath
        return typeof absolutePath === 'string' ? ([absolutePath, asset.id] as const) : undefined
      })
      .filter((entry): entry is readonly [string, string] => Boolean(entry)),
  )

  const events = buildEvents(selection.selectedEntries, assetIdByAbsolutePath)
  const toolCalls = events.filter(
    (event): event is ToolCallEvent => event.type === 'tool_call',
  )
  const toolResults = events.filter(
    (event): event is ToolResultEvent => event.type === 'tool_result',
  )
  const hooks = events.filter((event): event is HookEvent => event.type === 'hook')
  const agents = await parseAgentThreads(input.bundle, assetIdByAbsolutePath)

  const artifacts = [
    ...(await extractPlanArtifacts({
      bundle: input.bundle,
      assets,
      toolCalls,
      toolResults,
    })),
    ...extractQuestionArtifacts({ toolCalls, toolResults }),
    ...extractTodoArtifacts({ toolCalls }),
    ...extractToolDecisionArtifacts({ toolCalls, toolResults, hooks }),
    ...extractToolOutputArtifacts({ toolCalls, toolResults }),
  ] satisfies SessionArtifact[]

  const metadata = buildSessionMetadata(rawEntries, input.session)
  const metrics = buildClaudeCodeMetrics(rawEntries, {
    catalog: input.pricingCatalog,
  })

  return {
    kind: 'canonical_session',
    schemaVersion: 1,
    parserVersion: input.parserVersion,
    provider: 'claude_code',
    source: {
      sessionId: input.bundle.sessionId,
      projectKey: input.bundle.projectKey,
      projectPath: input.bundle.projectPath,
      sourceRevisionHash: input.bundle.files.map(file => file.sha256).join(':'),
      transcriptSha256: input.bundle.files[0]?.sha256 ?? '',
      importedAt: input.bundle.capturedAt,
    },
    metadata,
    selection: {
      strategy: 'latest_leaf',
      selectedLeafUuid: selection.selectedLeafUuid,
      branchCount: selection.branchCount,
    },
    stats: {
      visibleMessageCount: events.filter(
        event => event.type === 'user_message' || event.type === 'assistant_message',
      ).length,
      toolRunCount: toolCalls.length,
      artifactCount: artifacts.length,
      subagentCount: agents.length,
    },
    events,
    agents,
    assets,
    artifacts,
    searchText: buildSearchText({ metadata, events, artifacts }),
    providerData: {
      claudeCode: {
        slug: input.bundle.manifest.slug,
        cwd: input.bundle.manifest.cwd,
        gitBranch: input.bundle.manifest.gitBranch,
        metrics,
      },
    },
  }
}

const parseAgentThreads = async (
  bundle: SourceBundle,
  assetIdByAbsolutePath: Map<string, string>,
): Promise<AgentThread[]> => {
  return Promise.all(
    bundle.manifest.subagents.map(async subagent => {
      const rawEntries = await parseJsonlFile(subagent.transcriptAbsolutePath)
      const selection = selectActiveThread(rawEntries, { includeSidechain: true })

      return {
        agentId: subagent.agentId,
        title: subagent.description,
        role: 'subagent',
        events: buildEvents(selection.selectedEntries, assetIdByAbsolutePath) as CanonicalEvent[],
        metadata: {
          agentType: subagent.agentType,
          description: subagent.description,
        },
      }
    }),
  )
}

import type {
  CanonicalSession,
  PlanArtifact,
  QuestionArtifact,
  SessionArtifact,
} from '@howicc/canonical'
import type { MessageBlock, QuestionBlock, RenderBlock } from './block'
import type { RenderDocument } from './document'

const isPlanArtifact = (artifact: SessionArtifact): artifact is PlanArtifact =>
  artifact.artifactType === 'plan'

const isQuestionArtifact = (
  artifact: SessionArtifact,
): artifact is QuestionArtifact => artifact.artifactType === 'question_interaction'

const buildMessageBlocks = (session: CanonicalSession): MessageBlock[] =>
  session.events.flatMap<MessageBlock>(event => {
    if (event.type === 'user_message') {
      return [{ type: 'message', id: event.id, role: 'user', text: event.text }]
    }

    if (event.type === 'assistant_message') {
      return [
        { type: 'message', id: event.id, role: 'assistant', text: event.text },
      ]
    }

    return []
  })

const buildQuestionBlocks = (session: CanonicalSession): QuestionBlock[] =>
  session.artifacts.flatMap(artifact => {
    if (!isQuestionArtifact(artifact)) return []

    return [
      {
        type: 'question',
        id: artifact.id,
        title: 'Questions for the user',
        questions: artifact.questions.map(question => {
          const answer = artifact.answers?.[question.header]
          const annotation = artifact.annotations?.[question.header]

          return {
            ...question,
            answer,
            notes: annotation?.notes,
            selectedPreview: annotation?.preview,
          }
        }),
        outcome: artifact.outcome,
        feedbackText: artifact.feedbackText,
        defaultCollapsed: artifact.outcome !== 'answered',
      },
    ]
  })

export const buildRenderDocument = (
  session: CanonicalSession,
): RenderDocument => {
  const currentPlan = session.artifacts.find(
    (artifact): artifact is PlanArtifact =>
      isPlanArtifact(artifact) && artifact.role === 'main',
  )

  const blocks: RenderBlock[] = [
    ...buildMessageBlocks(session),
    ...buildQuestionBlocks(session),
  ]

  return {
    kind: 'render_document',
    schemaVersion: 1,
    session: {
      sessionId: session.source.sessionId,
      title:
        session.metadata.title ??
        session.metadata.customTitle ??
        session.metadata.summary ??
        session.source.sessionId,
      provider: session.provider,
      createdAt: session.metadata.createdAt,
      updatedAt: session.metadata.updatedAt,
      gitBranch: session.metadata.gitBranch,
      tag: session.metadata.tag,
      stats: {
        messageCount: session.stats.visibleMessageCount,
        toolRunCount: session.stats.toolRunCount,
        activityGroupCount: 0,
      },
    },
    context: currentPlan
      ? {
          currentPlan: {
            title: 'Current plan',
            body: currentPlan.content,
            source:
              currentPlan.resolutionSource === 'file'
                ? 'file'
                : 'transcript_recovered',
            filePath: currentPlan.filePath,
          },
        }
      : undefined,
    blocks,
  }
}

