// Inline the render logic since cross-package resolution is tricky with tsx
import type { CanonicalSession } from '@howicc/canonical'

const buildRenderSummary = (session: CanonicalSession) => {
  const userMessages = session.events.filter(e => e.type === 'user_message')
  const assistantMessages = session.events.filter(e => e.type === 'assistant_message')
  const toolCalls = session.events.filter(e => e.type === 'tool_call')
  const toolResults = session.events.filter(e => e.type === 'tool_result')
  const hooks = session.events.filter(e => e.type === 'hook')
  const systemNotices = session.events.filter(e => e.type === 'system_notice')
  const subagentRefs = session.events.filter(e => e.type === 'subagent_ref')
  const compactBoundaries = session.events.filter(e => e.type === 'compact_boundary')

  return {
    userMessages: userMessages.length,
    assistantMessages: assistantMessages.length,
    toolCalls: toolCalls.length,
    toolResults: toolResults.length,
    hooks: hooks.length,
    systemNotices: systemNotices.length,
    subagentRefs: subagentRefs.length,
    compactBoundaries: compactBoundaries.length,
  }
}

