type TurnEvent = typeof canonical.events[number]
type Turn = { userMessage?: TurnEvent; events: TurnEvent[] }

const turns: Turn[] = []
let currentTurn: Turn = { events: [] }

for (const event of canonical.events) {
  if (event.type === 'user_message') {
    if (currentTurn.userMessage || currentTurn.events.length > 0) {
      turns.push(currentTurn)
    }
    currentTurn = { userMessage: event, events: [] }
  } else {
    currentTurn.events.push(event)
  }
}
if (currentTurn.userMessage || currentTurn.events.length > 0) {
  turns.push(currentTurn)
}

console.log(`Total turns: ${turns.length}\n`)

for (let i = 0; i < turns.length; i++) {
  const turn = turns[i]!
  const toolCalls = turn.events.filter(e => e.type === 'tool_call') as Array<{ type: 'tool_call'; toolName: string; commentLabel?: string }>
  const toolResults = turn.events.filter(e => e.type === 'tool_result') as Array<{ type: 'tool_result'; status: string; text?: string }>
  const assistantMsgs = turn.events.filter(e => e.type === 'assistant_message') as Array<{ type: 'assistant_message'; text: string }>
  const hooks = turn.events.filter(e => e.type === 'hook')
  const subagentRefs = turn.events.filter(e => e.type === 'subagent_ref') as Array<{ type: 'subagent_ref'; label?: string; agentId: string }>
  const notices = turn.events.filter(e => e.type === 'system_notice') as Array<{ type: 'system_notice'; subtype: string; text: string }>

  console.log(`─── Turn ${i + 1} ───────────────────────────────────────────`)

  if (turn.userMessage && turn.userMessage.type === 'user_message') {
    const text = turn.userMessage.text.slice(0, 150) + (turn.userMessage.text.length > 150 ? '...' : '')
    console.log(`  👤 ${text}`)
  }

  for (const msg of assistantMsgs) {
    const isThinking = msg.text.startsWith('{"type":"thinking"')
    if (isThinking) {
      console.log(`  💭 [thinking — ${msg.text.length} chars]`)
    } else {
      const text = msg.text.slice(0, 150) + (msg.text.length > 150 ? '...' : '')
      console.log(`  🤖 ${text}`)
    }
  }

  if (toolCalls.length > 0) {
    // Group tool calls for an activity group summary
    const toolGroups: Record<string, number> = {}
    for (const tc of toolCalls) {
      toolGroups[tc.toolName] = (toolGroups[tc.toolName] ?? 0) + 1
    }
    const groupSummary = Object.entries(toolGroups).map(([name, count]) => count > 1 ? `${name} x${count}` : name).join(', ')
    const errorCount = toolResults.filter(r => r.status === 'error').length

    console.log(`  ⚙️  [${toolCalls.length} tool runs: ${groupSummary}]${errorCount > 0 ? ` (${errorCount} errors)` : ''}`)

    for (const tc of toolCalls) {
      const result = toolResults.find(r => 'toolUseId' in r && 'toolUseId' in tc && (r as any).toolUseId === (tc as any).toolUseId)
      const status = result?.status === 'ok' ? '✅' : result?.status === 'error' ? '❌' : '⚠️'
      console.log(`     ${status} ${tc.toolName}  ${tc.commentLabel ?? ''}`)
    }
  }

  for (const ref of subagentRefs) {
    console.log(`  🔀 Spawned agent: ${ref.label ?? ref.agentId}`)
  }

  for (const hook of hooks) {
    if ('hookEvent' in hook) {
      console.log(`  🪝 ${(hook as any).hookEvent} ${(hook as any).label ?? ''}`)
    }
  }

  for (const notice of notices) {
    if (notice.subtype !== 'turn_duration') {
      console.log(`  📢 ${notice.subtype}: ${notice.text.slice(0, 80)}`)
    }
  }

  console.log()
}

