/**
 * Runs the full pipeline + render layer on a session and shows what blocks are produced.
 * Usage: npx tsx src/__tests__/dump-render.ts <sessionId>
 */
import { buildClaudeCanonicalSession } from '../canonical'
import { buildClaudeSourceBundle } from '../bundle'
import { discoverClaudeSessions } from '../discover'
import { getClaudeHomeDir } from '../claudePaths'
// Inline the render logic since cross-package resolution is tricky with tsx
import type { CanonicalSession } from '@howicc/canonical'

const buildRenderSummary = (session: CanonicalSession) => {
  const userMessages = session.events.filter(e => e.type === 'user_message')
  const assistantMessages = session.events.filter(e => e.type === 'assistant_message')
  const toolCalls = session.events.filter(e => e.type === 'tool_call')
  const toolResults = session.events.filter(e => e.type === 'tool_result')
  const hooks = session.events.filter(e => e.type === 'hook')
  const systemNotices = session.events.filter(e => e.type === 'system_notice')
  const subagentRefs = session.events.filter(e => e.type === 'subagent_ref')
  const compactBoundaries = session.events.filter(e => e.type === 'compact_boundary')

  return {
    userMessages: userMessages.length,
    assistantMessages: assistantMessages.length,
    toolCalls: toolCalls.length,
    toolResults: toolResults.length,
    hooks: hooks.length,
    systemNotices: systemNotices.length,
    subagentRefs: subagentRefs.length,
    compactBoundaries: compactBoundaries.length,
  }
}

const sessionId = process.argv[2]
if (!sessionId) {
  console.error('Usage: npx tsx src/__tests__/dump-render.ts <sessionId>')
  process.exit(1)
}

const claudeHomeDir = getClaudeHomeDir()
const sessions = await discoverClaudeSessions({ claudeHomeDir })
const session = sessions.find(s => s.sessionId === sessionId)

if (!session) {
  console.error(`Session ${sessionId} not found`)
  process.exit(1)
}

const bundle = await buildClaudeSourceBundle(session, { claudeHomeDir })
const canonical = await buildClaudeCanonicalSession({
  bundle,
  session,
  parserVersion: 'dump-test-v0',
})

const renderDoc = buildRenderDocument(canonical)

console.log('=== RENDER DOCUMENT ===')
console.log(`Title:    ${renderDoc.session.title}`)
console.log(`Provider: ${renderDoc.session.provider}`)
console.log(`Created:  ${renderDoc.session.createdAt}`)
