console.log(`Plan:     ${renderDoc.context?.currentPlan ? 'yes' : 'no'}`)

console.log(`\nTotal blocks: ${renderDoc.blocks.length}`)

const blockCounts: Record<string, number> = {}
for (const block of renderDoc.blocks) {
  blockCounts[block.type] = (blockCounts[block.type] ?? 0) + 1
}
console.log('\nBlock type distribution:')
for (const [type, count] of Object.entries(blockCounts).sort((a, b) => b[1] - a[1])) {
  console.log(`  ${type}: ${count}`)
}

console.log('\n=== BLOCK STREAM (what the viewer would render) ===\n')

for (const block of renderDoc.blocks) {
  switch (block.type) {
    case 'message': {
      const prefix = block.role === 'user' ? '👤 USER' : '🤖 ASST'
      const text = block.text.slice(0, 200) + (block.text.length > 200 ? '...' : '')
      // check if it looks like raw JSON thinking blocks
      const isThinking = text.startsWith('{"type":"thinking"')
      if (isThinking) {
