import type { ParsedRawEntry } from '../jsonl'
import { asArray, getBoolean, getString, isRecord, type JsonRecord } from '../utils'

export type RawContentBlock = JsonRecord

const unwrapRaw = (entry: ParsedRawEntry | JsonRecord): JsonRecord => {
  if ('raw' in entry && isRecord(entry.raw)) {
    return entry.raw
  }

  return entry
}

export const getEntryType = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).type)

export const getEntryUuid = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).uuid)

export const getEntryParentUuid = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).parentUuid)

export const getEntryTimestamp = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).timestamp)

export const isSidechainEntry = (entry: ParsedRawEntry | JsonRecord): boolean =>
  getBoolean(unwrapRaw(entry).isSidechain) ?? false

export const getMessage = (
  entry: ParsedRawEntry | JsonRecord,
): JsonRecord | undefined => {
  const raw = unwrapRaw(entry)
  return isRecord(raw.message) ? raw.message : undefined
}

export const getMessageModel = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(getMessage(entry)?.model)

export const getMessageUsage = (
  entry: ParsedRawEntry | JsonRecord,
): JsonRecord | undefined => {
  const usage = getMessage(entry)?.usage
  return isRecord(usage) ? usage : undefined
}

export const getPermissionMode = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).permissionMode)

export const getSlug = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).slug)

export const getCwd = (entry: ParsedRawEntry | JsonRecord): string | undefined =>
  getString(unwrapRaw(entry).cwd)

export const getGitBranch = (
  entry: ParsedRawEntry | JsonRecord,
): string | undefined => getString(unwrapRaw(entry).gitBranch)

export const getTopLevelToolUseResult = (
  entry: ParsedRawEntry | JsonRecord,
): unknown => unwrapRaw(entry).toolUseResult

export const getMessageContent = (entry: ParsedRawEntry | JsonRecord): unknown =>
  getMessage(entry)?.content

export const getContentBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  asArray<unknown>(getMessageContent(entry)).filter(isRecord)

export const getTextBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'text')

export const getToolUseBlocks = (entry: ParsedRawEntry | JsonRecord): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'tool_use')

export const getToolResultBlocks = (
  entry: ParsedRawEntry | JsonRecord,
): RawContentBlock[] =>
  getContentBlocks(entry).filter(block => getString(block.type) === 'tool_result')

export const extractTextContent = (content: unknown): string | undefined => {
  if (typeof content === 'string') {
    return content
  }

  const parts = asArray<unknown>(content)
    .map(part => {
      if (typeof part === 'string') return part
      if (!isRecord(part)) return undefined

      if (getString(part.type) === 'text') {
        return getString(part.text)
      }

      if (getString(part.type) === 'tool_reference') {
        const toolName = getString(part.tool_name)
        return toolName ? `tool:${toolName}` : undefined
      }

      return JSON.stringify(part)
    })
    .filter((part): part is string => Boolean(part))

  return parts.length > 0 ? parts.join('\n\n') : undefined
}

export const extractPersistedOutputPath = (text: string): string | undefined => {
  const match = text.match(/Full output saved to:\s+(.+?)(?:\n|$)/)
  return match?.[1]?.trim()
}

import type {
  CanonicalEvent,
  HookEvent,
  SystemNoticeEvent,
  ToolCallEvent,
  ToolResultEvent,
} from '@howicc/canonical'
import type { ParsedRawEntry } from '../jsonl'
import {
  extractPersistedOutputPath,
  extractTextContent,
  getContentBlocks,
  getEntryTimestamp,
  getEntryType,
  getEntryUuid,
  getMessage,
  getToolResultBlocks,
  getToolUseBlocks,
  getTopLevelToolUseResult,
} from './raw'
import { getString, isRecord } from '../utils'

export const buildEvents = (
  entries: ParsedRawEntry[],
  assetIdByAbsolutePath: Map<string, string>,
): CanonicalEvent[] => {
  const events: CanonicalEvent[] = []

  for (const entry of entries) {
    const type = getEntryType(entry)

    if (type === 'assistant') {
      events.push(...buildAssistantEvents(entry))
      continue
    }

    if (type === 'user') {
      events.push(...buildUserEvents(entry, assetIdByAbsolutePath))
      continue
    }

    if (type === 'system') {
      const systemEvent = buildSystemEvent(entry)
      if (systemEvent) events.push(systemEvent)
    }
  }

  return events
}

const buildAssistantEvents = (entry: ParsedRawEntry): CanonicalEvent[] => {
  const events: CanonicalEvent[] = []
  const message = getMessage(entry)
  const textBlocks = getContentBlocks(entry).filter(
    block => getString(block.type) === 'text',
  )
  const assistantText = extractTextContent(textBlocks)

  if (assistantText) {
    events.push({
      type: 'assistant_message',
      id: `${entry.index}:assistant:text`,
      uuid: getEntryUuid(entry),
      parentUuid: getString(entry.raw.parentUuid),
      timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
      text: assistantText,
      isMeta: false,
      isApiErrorMessage: false,
    })
  }

  const toolUseBlocks = getToolUseBlocks(entry)

  for (const [index, block] of toolUseBlocks.entries()) {
    const toolUseId = getString(block.id)
    const toolName = getString(block.name)

    if (!toolUseId || !toolName) continue

    const input = isRecord(block.input) ? block.input : {}

    const toolCall: ToolCallEvent = {
      type: 'tool_call',
      id: `${entry.index}:assistant:tool:${index}`,
      toolUseId,
      assistantUuid: getEntryUuid(entry),
      timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
      toolName,
      displayName: toolName,
      source: toolName.startsWith('mcp__') ? 'mcp' : 'native',
      input,
      commentLabel: getString(input.description),
      mcpServerName: toolName.startsWith('mcp__')
        ? toolName.split('__')[1]
        : undefined,
    }

    events.push(toolCall)
  }

  if (!assistantText && toolUseBlocks.length === 0 && message) {
    const fallbackText = extractTextContent(message.content)

    if (fallbackText) {
      events.push({
        type: 'assistant_message',
        id: `${entry.index}:assistant:fallback`,
        uuid: getEntryUuid(entry),
        parentUuid: getString(entry.raw.parentUuid),
        timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
        text: fallbackText,
        isMeta: true,
        isApiErrorMessage: false,
      })
    }
  }

  return events
}

const buildUserEvents = (
  entry: ParsedRawEntry,
  assetIdByAbsolutePath: Map<string, string>,
): CanonicalEvent[] => {
  const content = getMessage(entry)?.content

  if (typeof content === 'string') {
    return [
      {
        type: 'user_message',
        id: `${entry.index}:user:text`,
        uuid: getEntryUuid(entry),
        parentUuid: getString(entry.raw.parentUuid),
        timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
        text: content,
        isMeta: false,
        origin: getString(entry.raw.entrypoint),
      },
    ]
  }

  const toolResultBlocks = getToolResultBlocks(entry)
  const events: CanonicalEvent[] = []

  for (const [index, block] of toolResultBlocks.entries()) {
    const toolUseId = getString(block.tool_use_id)
    if (!toolUseId) continue

    const text = extractTextContent(block.content)
    const topLevelResult = getTopLevelToolUseResult(entry)
    const persistedOutputPath = text ? extractPersistedOutputPath(text) : undefined

    const toolResult: ToolResultEvent = {
      type: 'tool_result',
      id: `${entry.index}:user:tool_result:${index}`,
      toolUseId,
      timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
      status: getToolResultStatus(block, topLevelResult),
      text,
      json: topLevelResult,
      artifactId: persistedOutputPath
        ? assetIdByAbsolutePath.get(persistedOutputPath)
        : undefined,
      mcpMeta: isRecord(entry.raw.mcpMeta) ? entry.raw.mcpMeta : undefined,
    }

    events.push(toolResult)
  }

  const userText = extractTextContent(
    getContentBlocks(entry).filter(block => getString(block.type) === 'text'),
  )

  if (userText) {
    events.push({
      type: 'user_message',
      id: `${entry.index}:user:fallback`,
      uuid: getEntryUuid(entry),
      parentUuid: getString(entry.raw.parentUuid),
      timestamp: getEntryTimestamp(entry) ?? new Date(0).toISOString(),
      text: userText,
      isMeta: false,
      origin: getString(entry.raw.entrypoint),
    })
  }

  return events
}

const buildSystemEvent = (entry: ParsedRawEntry): CanonicalEvent | undefined => {
  const subtype = getString(entry.raw.subtype)
  const timestamp = getEntryTimestamp(entry) ?? new Date(0).toISOString()

  if (subtype === 'stop_hook_summary') {
    const hookInfos = Array.isArray(entry.raw.hookInfos) ? entry.raw.hookInfos : []

    const hookEvent: HookEvent = {
      type: 'hook',
      id: `${entry.index}:system:stop_hook_summary`,
      timestamp,
      hookEvent: 'stop',
      toolUseId: getString(entry.raw.toolUseID),
      label: 'stop_hook_summary',
      text: hookInfos
        .map(hookInfo =>
          isRecord(hookInfo)
            ? `${getString(hookInfo.command) ?? 'unknown'} (${getString(hookInfo.durationMs) ?? hookInfo.durationMs ?? 'n/a'}ms)`
            : undefined,
        )
        .filter((value): value is string => Boolean(value))
        .join('\n'),
      preventedContinuation:
        typeof entry.raw.preventedContinuation === 'boolean'
          ? entry.raw.preventedContinuation
          : false,
    }

    return hookEvent
  }

  const notice: SystemNoticeEvent = {
    type: 'system_notice',
    id: `${entry.index}:system:${subtype ?? 'unknown'}`,
    timestamp,
    subtype: subtype ?? 'unknown',
    level: getString(entry.raw.level) as SystemNoticeEvent['level'] | undefined,
    text:
      extractTextContent(entry.raw.message) ??
      getString(entry.raw.stopReason) ??
      subtype ??
      'system notice',
    data: entry.raw,
  }

  return notice
}

const getToolResultStatus = (
  block: Record<string, unknown>,
  topLevelResult: unknown,
): ToolResultEvent['status'] => {
  if (block.is_error === true) {
    return 'error'
  }

  if (isRecord(topLevelResult) && topLevelResult.interrupted === true) {
    return 'partial'
  }

  return 'ok'
}

