// ---------------------------------------------------------------------------
// Targeted session tests — uses a known real conversation to assert specific
// pipeline behaviors against real CC transcript structure.
// ---------------------------------------------------------------------------

const TARGET_SESSION_ID = 'f40fecf9-e6c8-4c57-ac3a-2eacd12cd428'

const describeWithTargetSession = await hasTargetSession(claudeHomeDir, TARGET_SESSION_ID)
  ? describe
  : describe.skip

describeWithTargetSession(`targeted pipeline tests (session ${TARGET_SESSION_ID.slice(0, 8)})`, () => {
  let canonical: Awaited<ReturnType<typeof parseRealSession>>

  // Parse once, share across tests
  const getCanonical = async () => {
    if (!canonical) {
      const sessions = await discoverClaudeSessions({ claudeHomeDir })
      const session = sessions.find(s => s.sessionId === TARGET_SESSION_ID)!
      canonical = await parseRealSession(session)
    }
    return canonical
  }

  // -- Token deduplication --------------------------------------------------

  it('does not overcount tokens from multi-block API responses', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    // The raw JSONL has 97 assistant entries, many sharing usage snapshots.
    // Naive sum: ~33K input. Deduplicated: ~14K input.
    // We assert that deduplication cuts input tokens by at least 30%.
    expect(metrics.inputTokens).toBeLessThan(25_000)
    expect(metrics.inputTokens).toBeGreaterThan(5_000)

    // Cache tokens had the worst inflation (3.1x). Deduplicated should be
    // significantly lower than naive sum.
    expect(metrics.cacheCreationInputTokens).toBeLessThan(800_000)
    expect(metrics.cacheReadInputTokens).toBeLessThan(5_000_000)

    // Output tokens should still be reasonable (barely affected by dedup)
    expect(metrics.outputTokens).toBeGreaterThan(10_000)
    expect(metrics.outputTokens).toBeLessThan(60_000)
  })

  it('produces one usage timeline entry per API response, not per content block', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    // This session has ~42 distinct API responses across 11 turns.
    // Each should produce exactly one timeline entry.
    // Naive approach would produce ~97 entries (one per assistant JSONL entry).
    expect(metrics.usageTimeline.length).toBeLessThan(60)
    expect(metrics.usageTimeline.length).toBeGreaterThan(10)
  })

  // -- Thinking block filtering ---------------------------------------------

  it('does not produce assistant messages containing raw thinking JSON', async () => {
    const session = await getCanonical()

    const assistantMessages = session.events.filter(e => e.type === 'assistant_message')

    for (const msg of assistantMessages) {
      if (msg.type !== 'assistant_message') continue
      expect(msg.text).not.toMatch(/^\{"type":"thinking"/)
      expect(msg.text).not.toContain('"signature":"')
    }
  })

  it('has fewer assistant messages than raw assistant entries (thinking blocks filtered)', async () => {
    const session = await getCanonical()

    // Raw JSONL has 97 assistant entries. Many are thinking-only blocks.
    // After filtering, assistant_message events should be significantly fewer.
    const assistantMessages = session.events.filter(e => e.type === 'assistant_message')
    expect(assistantMessages.length).toBeLessThan(50)
    expect(assistantMessages.length).toBeGreaterThan(5)
  })

  // -- Image handling -------------------------------------------------------

  it('preserves image context in user messages as placeholder text', async () => {
    const session = await getCanonical()

    const userMessages = session.events.filter(e => e.type === 'user_message')
    const imageMessages = userMessages.filter(
      msg => msg.type === 'user_message' && msg.text.includes('image')
    )

    // This conversation has a turn with 3 screenshots attached
    expect(imageMessages.length).toBeGreaterThan(0)

    const msgWithImages = imageMessages.find(
      msg => msg.type === 'user_message' && msg.text.includes('attached')
    )
    expect(msgWithImages).toBeTruthy()
    if (msgWithImages?.type === 'user_message') {
      expect(msgWithImages.text).toContain('3 images attached')
    }
  })

  // -- Tool labels ----------------------------------------------------------

  it('derives meaningful labels for Read, Glob, Bash, and Agent tool calls', async () => {
    const session = await getCanonical()

    const toolCalls = session.events.filter(e => e.type === 'tool_call') as Array<{
      type: 'tool_call'
      toolName: string
      commentLabel?: string
    }>

    const readCalls = toolCalls.filter(tc => tc.toolName === 'Read')
    const globCalls = toolCalls.filter(tc => tc.toolName === 'Glob')
    const agentCalls = toolCalls.filter(tc => tc.toolName === 'Agent')

    // Read calls should have file paths as labels
    const readWithLabel = readCalls.filter(tc => tc.commentLabel && tc.commentLabel.includes('/'))
    expect(readWithLabel.length).toBeGreaterThan(0)

    // Glob calls should have glob patterns as labels
    const globWithLabel = globCalls.filter(tc => tc.commentLabel && tc.commentLabel.includes('*'))
    expect(globWithLabel.length).toBeGreaterThan(0)

    // Agent calls should have prompt content as labels
    const agentWithLabel = agentCalls.filter(tc => tc.commentLabel && tc.commentLabel.length > 10)
    expect(agentWithLabel.length).toBeGreaterThan(0)
  })

  // -- Turn counting --------------------------------------------------------

  it('counts turns from selected thread only, excluding dead branches', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    // Raw JSONL has 12 unique promptIds but 2 are from dead branches
    // (user edited prompt). The pipeline should report 10 actual turns.
    expect(metrics.turnCount).toBeLessThanOrEqual(11)
    expect(metrics.turnCount).toBeGreaterThanOrEqual(8)
  })

  // -- Thread selection -----------------------------------------------------

  it('selects the active thread and excludes dead-branch user messages', async () => {
    const session = await getCanonical()

    const userMessages = session.events.filter(e => e.type === 'user_message')

    // The session has 2 pairs of same-parent user messages (entries 35/37, 76/78).
    // Only the sent versions (37, 78) should appear in the selected thread.
    // Check that there are no duplicate user messages with nearly identical text.
    const texts = userMessages
      .filter(e => e.type === 'user_message')
      .map(e => (e as { text: string }).text.slice(0, 50))

    const uniqueTexts = new Set(texts)
    expect(uniqueTexts.size).toBe(texts.length)
  })

  // -- Subagents ------------------------------------------------------------

  it('discovers and parses all subagent threads', async () => {
    const session = await getCanonical()

    // This conversation spawned 5 Explore subagents
    expect(session.agents.length).toBe(5)

    for (const agent of session.agents) {
      expect(agent.role).toBe('subagent')
      expect(agent.events.length).toBeGreaterThan(0)
      expect(agent.title).toBeTruthy()
    }
  })

  // -- Artifacts ------------------------------------------------------------

  it('detects tool decision artifacts for rejected/errored tool calls', async () => {
    const session = await getCanonical()

    const toolDecisions = session.artifacts.filter(a => a.artifactType === 'tool_decision')

    // The session has: 1 interrupted Agent, 2 failed Bash (tsx not found)
    expect(toolDecisions.length).toBeGreaterThanOrEqual(3)
  })

  it('extracts tool output artifacts with preview text', async () => {
    const session = await getCanonical()

    const toolOutputs = session.artifacts.filter(a => a.artifactType === 'tool_output')
    expect(toolOutputs.length).toBeGreaterThan(20)

    const withPreviews = toolOutputs.filter(
      a => a.artifactType === 'tool_output' && a.previewText && a.previewText.length > 0,
    )
    expect(withPreviews.length).toBeGreaterThan(10)
  })

  // -- Overall session structure --------------------------------------------

  it('produces a well-formed canonical session with expected structure', async () => {
    const session = await getCanonical()

    expect(session.kind).toBe('canonical_session')
    expect(session.schemaVersion).toBe(1)
    expect(session.provider).toBe('claude_code')
    expect(session.source.sessionId).toBe(TARGET_SESSION_ID)
    expect(session.metadata.gitBranch).toBe('chore/howicc-revamp-foundation')
    expect(session.metadata.createdAt).toBeTruthy()
    expect(session.metadata.updatedAt).toBeTruthy()

    // Should have reasonable event counts
    expect(session.stats.visibleMessageCount).toBeGreaterThan(20)
    expect(session.stats.toolRunCount).toBeGreaterThan(30)
    expect(session.stats.subagentCount).toBe(5)

    // Should have search text
    expect(session.searchText.length).toBeGreaterThan(1000)
  })

  it('has model set to claude-opus-4-6 throughout', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    expect(metrics.modelsUsed).toEqual(['claude-opus-4-6'])
    expect(metrics.modelTimeline).toHaveLength(1)
    expect(metrics.modelTimeline[0]!.model).toBe('claude-opus-4-6')
  })

  it('computes a duration of roughly 80 minutes', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    const durationMinutes = (metrics.durationMs ?? 0) / 1000 / 60
    expect(durationMinutes).toBeGreaterThan(60)
    expect(durationMinutes).toBeLessThan(120)
  })
})

