    await mkdir(projectDirectory, { recursive: true })

    const lines = [
      {
        type: 'user',
        uuid: 'u1',
        parentUuid: null,
        promptId: 'p1',
        timestamp: '2026-04-01T10:00:00.000Z',
        permissionMode: 'acceptEdits',
