        },
      },
      {
        type: 'assistant',
        uuid: 'a2',
        parentUuid: 'u2-plan',
        timestamp: '2026-04-01T10:00:08.000Z',
        cwd: projectPath,
        gitBranch: 'main',
        slug: 'metrics-river',
        message: {
          role: 'assistant',
          model: 'claude-haiku-4-5-20251001',
          usage: {
            input_tokens: 12,
            output_tokens: 4,
            cache_creation_input_tokens: 0,
            cache_read_input_tokens: 1,
          },
          content: [
            {
              type: 'tool_use',
              id: 'exit-plan',
              name: 'ExitPlanMode',
              input: { plan: '# Plan\n\nDo thing' },
            },
            { type: 'text', text: 'second answer' },
