            for block in d.get('message', {}).get('content', []):
                if isinstance(block, dict) and block.get('type') == 'thinking':
                    if block.get('thinking', '').strip():
                        has_content += 1
                    elif block.get('signature'):
                        signature_only += 1
    except:
        continue

    if has_content > 0 and signature_only > 0:
        print(f'Mixed session: {session_id}  content={has_content}  redacted={signature_only}')
        # Show the transition point
        content_seen = False
        redacted_seen = False
        for i, line in enumerate(lines):
            d = json.loads(line.strip())
            if d.get('type') != 'assistant':
                continue
            for block in d.get('message', {}).get('content', []):
                if isinstance(block, dict) and block.get('type') == 'thinking':
