                    ts = d.get('timestamp', '')[:19]
                    model = d.get('message', {}).get('model', '')
                    if has_text and not content_seen:
                        print(f'  First content at entry {i}: {ts} model={model}')
                        content_seen = True
                    if not has_text and block.get('signature') and not redacted_seen:
                        print(f'  First redacted at entry {i}: {ts} model={model}')
                        redacted_seen = True

