/**
 * Quick prototype: extract session digests from real ~/.claude data
 * and aggregate into a user profile to see what the data looks like.
 *
 * Usage: ./node_modules/.bin/tsx src/__tests__/prototype-profile.ts
 */
import { buildClaudeCanonicalSession } from '../canonical'
import { buildClaudeSourceBundle } from '../bundle'
import { discoverClaudeSessions } from '../discover'
import { getClaudeHomeDir } from '../claudePaths'
import type { CanonicalSession } from '@howicc/canonical'

// ---------------------------------------------------------------------------
// Tool category mapping
// ---------------------------------------------------------------------------

type ToolCategory = 'read' | 'write' | 'search' | 'command' | 'agent' | 'mcp' | 'plan' | 'question' | 'task' | 'web' | 'other'

const categorizeToolName = (name: string): ToolCategory => {
  if (name.startsWith('mcp__')) return 'mcp'
  switch (name) {
    case 'Read': case 'NotebookRead': return 'read'
    case 'Edit': case 'Write': case 'NotebookEdit': return 'write'
    case 'Grep': case 'Glob': return 'search'
    case 'Bash': return 'command'
    case 'Agent': case 'SendMessage': return 'agent'
    case 'EnterPlanMode': case 'ExitPlanMode': return 'plan'
    case 'AskUserQuestion': return 'question'
    case 'TaskCreate': case 'TaskUpdate': case 'TaskGet': case 'TaskList': return 'task'
    case 'WebFetch': case 'WebSearch': return 'web'
    default: return 'other'
  }
}

// ---------------------------------------------------------------------------
// Session digest
// ---------------------------------------------------------------------------

type SessionDigest = {
  sessionId: string
  provider: string
  projectKey: string
  projectPath?: string
  gitBranch?: string
  createdAt: string
  updatedAt: string
  durationMs: number
  turnCount: number
  messageCount: number
  toolRunCount: number
  toolCategories: Record<ToolCategory, number>
  errorCount: number
  rejectionCount: number
  interruptionCount: number
  subagentCount: number
  hasPlan: boolean
  hasThinking: boolean
  models: Array<{ model: string; inputTokens: number; outputTokens: number }>
  estimatedCostUsd?: number
  hourOfDay: number
}

const extractDigest = (session: CanonicalSession): SessionDigest => {
  const metrics = (session.providerData?.claudeCode as Record<string, unknown>)?.metrics as Record<string, unknown> | undefined

  const toolCategories: Record<ToolCategory, number> = {
    read: 0, write: 0, search: 0, command: 0, agent: 0,
    mcp: 0, plan: 0, question: 0, task: 0, web: 0, other: 0,
  }

  let errorCount = 0
  let interruptionCount = 0

  for (const event of session.events) {
    if (event.type === 'tool_call') {
      const cat = categorizeToolName(event.toolName)
      toolCategories[cat] += 1
    }
    if (event.type === 'tool_result' && event.status === 'error') {
      errorCount += 1
    }
    if (event.type === 'user_message' && event.text.includes('[Request interrupted by user')) {
      interruptionCount += 1
    }
  }

  const rejectionCount = session.artifacts.filter(a => a.artifactType === 'tool_decision').length
  const hasPlan = session.artifacts.some(a => a.artifactType === 'plan')
  const hasThinking = session.events.some(e => e.type === 'assistant_message' && e.isMeta === true)

  const usageTimeline = (metrics?.usageTimeline as Array<{ model: string; inputTokens: number; outputTokens: number }>) ?? []
  const modelAgg = new Map<string, { inputTokens: number; outputTokens: number }>()
  for (const entry of usageTimeline) {
    const existing = modelAgg.get(entry.model) ?? { inputTokens: 0, outputTokens: 0 }
    existing.inputTokens += entry.inputTokens
    existing.outputTokens += entry.outputTokens
    modelAgg.set(entry.model, existing)
  }

  const createdAt = session.metadata.createdAt
  const hourOfDay = new Date(createdAt).getHours()

  return {
    sessionId: session.source.sessionId,
    provider: session.provider,
    projectKey: session.source.projectKey,
    projectPath: session.metadata.cwd,
    gitBranch: session.metadata.gitBranch,
    createdAt,
    updatedAt: session.metadata.updatedAt,
    durationMs: (metrics?.durationMs as number) ?? 0,
    turnCount: (metrics?.turnCount as number) ?? 0,
    messageCount: session.stats.visibleMessageCount,
    toolRunCount: session.stats.toolRunCount,
    toolCategories,
    errorCount,
    rejectionCount,
    interruptionCount,
    subagentCount: session.stats.subagentCount,
    hasPlan,
    hasThinking,
    models: [...modelAgg.entries()].map(([model, usage]) => ({ model, ...usage })),
    estimatedCostUsd: metrics?.estimatedCostUsd as number | undefined,
    hourOfDay,
  }
}

// ---------------------------------------------------------------------------
// Profile aggregator
// ---------------------------------------------------------------------------

type UserProfile = {
  computedAt: string
  sessionCount: number
  providerBreakdown: Record<string, number>
  activity: {
    totalDurationMs: number
    totalTurns: number
    totalMessages: number
    firstSessionAt: string
    lastSessionAt: string
    activeDays: number
    longestStreakDays: number
    currentStreakDays: number
    averageSessionDurationMs: number
    averageTurnsPerSession: number
    hourlyDistribution: number[]
  }
  projects: Array<{
    projectKey: string
    projectPath?: string
    sessionCount: number
    totalDurationMs: number
    lastActiveAt: string
    branches: string[]
  }>
  toolcraft: {
    totalToolRuns: number
    categories: Record<ToolCategory, number>
    errorRate: number
    rejectionRate: number
    interruptionRate: number
    planUsageRate: number
    subagentUsageRate: number
    thinkingVisibleRate: number
  }
  models: Array<{
    model: string
    sessionCount: number
    totalInputTokens: number
    totalOutputTokens: number
    estimatedCostUsd: number
  }>
  cost: {
    totalEstimatedCostUsd: number
    averageCostPerSession: number
    costByMonth: Array<{ month: string; costUsd: number }>
  }
}

const buildProfile = (digests: SessionDigest[]): UserProfile => {
  const sorted = [...digests].sort((a, b) => a.createdAt.localeCompare(b.createdAt))

  // Activity
  const hourlyDistribution = new Array(24).fill(0) as number[]
  const activeDates = new Set<string>()
  let totalDurationMs = 0
  let totalTurns = 0
  let totalMessages = 0
  let totalToolRuns = 0
  let totalErrors = 0
  let totalRejections = 0
  let totalInterruptions = 0
  let sessionsWithPlan = 0
  let sessionsWithAgents = 0
  let sessionsWithThinking = 0

  const categories: Record<ToolCategory, number> = {
    read: 0, write: 0, search: 0, command: 0, agent: 0,
    mcp: 0, plan: 0, question: 0, task: 0, web: 0, other: 0,
  }

  const providerBreakdown: Record<string, number> = {}
  const projectMap = new Map<string, {
    projectPath?: string
    sessionCount: number
    totalDurationMs: number
    lastActiveAt: string
    branches: Set<string>
  }>()

  const modelMap = new Map<string, {
    sessionCount: number
    totalInputTokens: number
    totalOutputTokens: number
    estimatedCostUsd: number
  }>()

  const costByMonth = new Map<string, number>()

  for (const d of sorted) {
    totalDurationMs += d.durationMs
    totalTurns += d.turnCount
    totalMessages += d.messageCount
    totalToolRuns += d.toolRunCount
    totalErrors += d.errorCount
    totalRejections += d.rejectionCount
    totalInterruptions += d.interruptionCount
    if (d.hasPlan) sessionsWithPlan += 1
    if (d.subagentCount > 0) sessionsWithAgents += 1
    if (d.hasThinking) sessionsWithThinking += 1

    hourlyDistribution[d.hourOfDay] += 1

    const dateKey = d.createdAt.slice(0, 10)
    activeDates.add(dateKey)

    providerBreakdown[d.provider] = (providerBreakdown[d.provider] ?? 0) + 1

    for (const [cat, count] of Object.entries(d.toolCategories)) {
      categories[cat as ToolCategory] += count
    }

    const proj = projectMap.get(d.projectKey) ?? {
      projectPath: d.projectPath,
      sessionCount: 0,
      totalDurationMs: 0,
      lastActiveAt: d.updatedAt,
      branches: new Set<string>(),
    }
    proj.sessionCount += 1
    proj.totalDurationMs += d.durationMs
    proj.lastActiveAt = d.updatedAt > proj.lastActiveAt ? d.updatedAt : proj.lastActiveAt
    if (d.gitBranch) proj.branches.add(d.gitBranch)
    projectMap.set(d.projectKey, proj)

    for (const m of d.models) {
      const existing = modelMap.get(m.model) ?? {
        sessionCount: 0,
        totalInputTokens: 0,
        totalOutputTokens: 0,
        estimatedCostUsd: 0,
      }
      existing.totalInputTokens += m.inputTokens
      existing.totalOutputTokens += m.outputTokens
      modelMap.set(m.model, existing)
    }

    // Count session per model (may use multiple models)
    const sessionModels = new Set(d.models.map(m => m.model))
    for (const model of sessionModels) {
      const m = modelMap.get(model)!
      m.sessionCount += 1
    }

    if (d.estimatedCostUsd != null) {
      const month = d.createdAt.slice(0, 7)
      costByMonth.set(month, (costByMonth.get(month) ?? 0) + d.estimatedCostUsd)

      for (const m of d.models) {
        const existing = modelMap.get(m.model)
        if (existing) {
          // Proportional cost attribution
          const totalSessionTokens = d.models.reduce((sum, x) => sum + x.inputTokens + x.outputTokens, 0)
          const modelTokens = m.inputTokens + m.outputTokens
          const share = totalSessionTokens > 0 ? modelTokens / totalSessionTokens : 0
          existing.estimatedCostUsd += (d.estimatedCostUsd ?? 0) * share
        }
      }
    }
  }

  // Streaks
  const sortedDates = [...activeDates].sort()
  let longestStreak = 0
  let currentStreak = 0
  let tempStreak = 1

  const today = new Date().toISOString().slice(0, 10)
  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10)

  for (let i = 1; i < sortedDates.length; i++) {
    const prev = new Date(sortedDates[i - 1]!)
    const curr = new Date(sortedDates[i]!)
    const diffDays = (curr.getTime() - prev.getTime()) / 86400000

    if (diffDays === 1) {
      tempStreak += 1
    } else {
      longestStreak = Math.max(longestStreak, tempStreak)
      tempStreak = 1
    }
  }
  longestStreak = Math.max(longestStreak, tempStreak)

  // Current streak: count backwards from today
  currentStreak = 0
  if (activeDates.has(today) || activeDates.has(yesterday)) {
    let checkDate = activeDates.has(today) ? today : yesterday
    while (activeDates.has(checkDate)) {
      currentStreak += 1
      const d = new Date(checkDate)
      d.setDate(d.getDate() - 1)
      checkDate = d.toISOString().slice(0, 10)
    }
  }

  const n = sorted.length

  const totalCost = sorted.reduce((sum, d) => sum + (d.estimatedCostUsd ?? 0), 0)

  return {
    computedAt: new Date().toISOString(),
    sessionCount: n,
    providerBreakdown,
    activity: {
      totalDurationMs,
      totalTurns,
      totalMessages,
      firstSessionAt: sorted[0]?.createdAt ?? '',
      lastSessionAt: sorted[n - 1]?.updatedAt ?? '',
      activeDays: activeDates.size,
      longestStreakDays: longestStreak,
      currentStreakDays: currentStreak,
      averageSessionDurationMs: n > 0 ? totalDurationMs / n : 0,
      averageTurnsPerSession: n > 0 ? totalTurns / n : 0,
      hourlyDistribution,
    },
    projects: [...projectMap.entries()]
      .map(([key, p]) => ({
        projectKey: key,
        projectPath: p.projectPath,
        sessionCount: p.sessionCount,
        totalDurationMs: p.totalDurationMs,
        lastActiveAt: p.lastActiveAt,
        branches: [...p.branches],
      }))
      .sort((a, b) => b.sessionCount - a.sessionCount),
    toolcraft: {
      totalToolRuns,
      categories,
      errorRate: totalToolRuns > 0 ? totalErrors / totalToolRuns : 0,
      rejectionRate: totalToolRuns > 0 ? totalRejections / totalToolRuns : 0,
      interruptionRate: n > 0 ? totalInterruptions / n : 0,
      planUsageRate: n > 0 ? sessionsWithPlan / n : 0,
      subagentUsageRate: n > 0 ? sessionsWithAgents / n : 0,
      thinkingVisibleRate: n > 0 ? sessionsWithThinking / n : 0,
    },
    models: [...modelMap.entries()]
      .map(([model, m]) => ({ model, ...m }))
      .sort((a, b) => b.sessionCount - a.sessionCount),
    cost: {
      totalEstimatedCostUsd: totalCost,
      averageCostPerSession: n > 0 ? totalCost / n : 0,
      costByMonth: [...costByMonth.entries()]
        .map(([month, costUsd]) => ({ month, costUsd }))
        .sort((a, b) => a.month.localeCompare(b.month)),
    },
  }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

const main = async () => {
  const claudeHomeDir = getClaudeHomeDir()
  console.log(`Scanning ${claudeHomeDir}/projects/ ...`)

  const sessions = await discoverClaudeSessions({ claudeHomeDir })
  console.log(`Found ${sessions.length} sessions`)

  const digests: SessionDigest[] = []
  let errors = 0

  for (let i = 0; i < sessions.length; i++) {
    const session = sessions[i]!
    try {
      const bundle = await buildClaudeSourceBundle(session, { claudeHomeDir })
      const canonical = await buildClaudeCanonicalSession({
        bundle,
        session,
        parserVersion: 'prototype-v0',
      })
      digests.push(extractDigest(canonical))
      process.stdout.write(`\r  Parsed ${i + 1}/${sessions.length} sessions (${errors} errors)`)
    } catch {
      errors += 1
      process.stdout.write(`\r  Parsed ${i + 1}/${sessions.length} sessions (${errors} errors)`)
    }
  }

  console.log('\n')
  console.log(`Successfully digested ${digests.length} sessions (${errors} failed)`)

  const profile = buildProfile(digests)

  // Print the profile
  const mins = (ms: number) => `${Math.round(ms / 60000)}m`
  const hours = (ms: number) => `${(ms / 3600000).toFixed(1)}h`
  const pct = (n: number) => `${(n * 100).toFixed(1)}%`
  const usd = (n: number) => `$${n.toFixed(2)}`

  console.log('═══════════════════════════════════════════════════════════════')
  console.log('  YOUR AI CODING PROFILE')
  console.log('═══════════════════════════════════════════════════════════════')
  console.log()
  console.log(`  Sessions:      ${profile.sessionCount}`)
  console.log(`  Active days:   ${profile.activity.activeDays}`)
  console.log(`  Total time:    ${hours(profile.activity.totalDurationMs)}`)
  console.log(`  Total turns:   ${profile.activity.totalTurns}`)
  console.log(`  First session: ${profile.activity.firstSessionAt.slice(0, 10)}`)
  console.log(`  Last session:  ${profile.activity.lastSessionAt.slice(0, 10)}`)
  console.log(`  Streak:        ${profile.activity.currentStreakDays} days (longest: ${profile.activity.longestStreakDays})`)
  console.log(`  Avg session:   ${mins(profile.activity.averageSessionDurationMs)} · ${profile.activity.averageTurnsPerSession.toFixed(1)} turns`)
  console.log(`  Providers:     ${Object.entries(profile.providerBreakdown).map(([p, c]) => `${p} (${c})`).join(', ')}`)

  console.log()
  console.log('─── PROJECTS ────────────────────────────────────────────────')
  for (const p of profile.projects.slice(0, 10)) {
    const name = p.projectPath?.split('/').pop() ?? p.projectKey
    const bar = '█'.repeat(Math.ceil(p.sessionCount / profile.sessionCount * 30))
    console.log(`  ${name.padEnd(30)} ${bar.padEnd(30)} ${String(p.sessionCount).padStart(3)} sessions  ${hours(p.totalDurationMs)}`)
  }
  if (profile.projects.length > 10) {
    console.log(`  ... and ${profile.projects.length - 10} more projects`)
  }

  console.log()
  console.log('─── TOOLS & STYLE ───────────────────────────────────────────')
  const totalTools = profile.toolcraft.totalToolRuns
  const sortedCats = Object.entries(profile.toolcraft.categories)
    .sort((a, b) => b[1] - a[1])
    .filter(([, count]) => count > 0)

  for (const [cat, count] of sortedCats) {
    const bar = '█'.repeat(Math.ceil(count / totalTools * 40))
    console.log(`  ${cat.padEnd(10)} ${bar.padEnd(40)} ${String(count).padStart(5)}  ${pct(count / totalTools)}`)
  }
  console.log()
  console.log(`  Error rate:        ${pct(profile.toolcraft.errorRate)}`)
  console.log(`  Rejection rate:    ${pct(profile.toolcraft.rejectionRate)}`)
  console.log(`  Interruptions/ses: ${profile.toolcraft.interruptionRate.toFixed(2)}`)
  console.log(`  Plan usage:        ${pct(profile.toolcraft.planUsageRate)}`)
  console.log(`  Agent usage:       ${pct(profile.toolcraft.subagentUsageRate)}`)
  console.log(`  Thinking visible:  ${pct(profile.toolcraft.thinkingVisibleRate)}`)

  console.log()
  console.log('─── MODELS ──────────────────────────────────────────────────')
  for (const m of profile.models) {
    const totalTokens = m.totalInputTokens + m.totalOutputTokens
    const tokenStr = totalTokens > 1_000_000 ? `${(totalTokens / 1_000_000).toFixed(1)}M` : `${(totalTokens / 1000).toFixed(0)}K`
    console.log(`  ${m.model.padEnd(30)} ${String(m.sessionCount).padStart(4)} sessions  ${tokenStr.padStart(8)} tokens  ${usd(m.estimatedCostUsd)}`)
  }

  console.log()
  console.log('─── COST ────────────────────────────────────────────────────')
  console.log(`  Total:     ${usd(profile.cost.totalEstimatedCostUsd)}`)
  console.log(`  Avg/sess:  ${usd(profile.cost.averageCostPerSession)}`)
  if (profile.cost.costByMonth.length > 0) {
    console.log(`  By month:`)
    for (const { month, costUsd } of profile.cost.costByMonth) {
      const bar = '█'.repeat(Math.ceil(costUsd / Math.max(...profile.cost.costByMonth.map(m => m.costUsd)) * 30))
      console.log(`    ${month}  ${bar.padEnd(30)} ${usd(costUsd)}`)
    }
  }

  console.log()
  console.log('─── ACTIVITY PATTERN ────────────────────────────────────────')
  const maxHour = Math.max(...profile.activity.hourlyDistribution)
  const hourLabels = ['12a', ' 1a', ' 2a', ' 3a', ' 4a', ' 5a', ' 6a', ' 7a', ' 8a', ' 9a', '10a', '11a', '12p', ' 1p', ' 2p', ' 3p', ' 4p', ' 5p', ' 6p', ' 7p', ' 8p', ' 9p', '10p', '11p']

  // Vertical histogram
  const histHeight = 8
  for (let row = histHeight; row >= 1; row--) {
    const threshold = (row / histHeight) * maxHour
    let line = '  '
    for (let h = 0; h < 24; h++) {
      line += profile.activity.hourlyDistribution[h]! >= threshold ? '██' : '  '
    }
    console.log(line)
  }
  console.log(`  ${hourLabels.map(l => l.slice(-2)).join('')}`)
  console.log(`  Peak: ${hourLabels[profile.activity.hourlyDistribution.indexOf(maxHour)]} (${maxHour} sessions)`)
}

main().catch(console.error)

