import { and, desc, eq } from 'drizzle-orm'
import { createD1DatabaseAdapter } from '@howicc/db/adapters/d1'
import { modelCatalogEntries, modelCatalogSnapshots } from '@howicc/db/schema'
import type { ModelCatalogEntryRecord, ModelCatalogSnapshotRecord } from '@howicc/db/types'
import { createR2StorageAdapter } from '@howicc/storage/adapters/r2'
import { buildModelCatalogSnapshotKey } from '@howicc/storage/paths'
import { fetchOpenRouterCatalogPayload, normalizeOpenRouterCatalog, type OpenRouterCatalog } from '@howicc/model-pricing'
import type { ApiRuntime } from '../../runtime'

type PersistedCatalogResult = {
  snapshot: {
    id: string
    provider: string
    sourceUrl: string
    sourceHash: string
    modelCount: number
    fetchedAt: string
    rawCatalogStorageKey: string
    createdAt: string
  }
  models: OpenRouterCatalog['models']
}

export const refreshOpenRouterCatalogSnapshot = async (
  runtime: ApiRuntime,
  input?: { fetch?: typeof fetch },
): Promise<PersistedCatalogResult> => {
  const db = getD1Database(runtime)
  const storage = getR2Storage(runtime)

  const { payload, fetchedAt, rawJson, sourceUrl } = await fetchOpenRouterCatalogPayload({
    fetch: input?.fetch,
  })

  const catalog = normalizeOpenRouterCatalog(payload, { fetchedAt })
  const sourceHash = await sha256Hex(rawJson)

  const existing = await db
    .select()
    .from(modelCatalogSnapshots)
    .where(
      and(
        eq(modelCatalogSnapshots.provider, 'openrouter'),
        eq(modelCatalogSnapshots.sourceHash, sourceHash),
      ),
    )
    .limit(1)

  if (existing[0]) {
    const models = await db
      .select()
      .from(modelCatalogEntries)
      .where(eq(modelCatalogEntries.snapshotId, existing[0].id))

    return {
      snapshot: toSnapshotResponse(existing[0]),
      models: models.map(toCatalogModelResponse),
    }
  }

  const snapshotId = `catalog_${sourceHash.slice(0, 16)}`
  const rawCatalogStorageKey = buildModelCatalogSnapshotKey('openrouter', snapshotId)

  await storage.putObject({
    key: rawCatalogStorageKey,
    body: rawJson,
    contentType: 'application/json',
    metadata: {
      provider: 'openrouter',
      fetchedAt,
      sourceHash,
    },
  })

  const now = new Date()

  await db.insert(modelCatalogSnapshots).values({
    id: snapshotId,
    provider: 'openrouter',
    sourceUrl,
    sourceHash,
    modelCount: catalog.models.length,
    fetchedAt: new Date(fetchedAt),
    rawCatalogStorageKey,
    createdAt: now,
  })

  await db.insert(modelCatalogEntries).values(
    catalog.models.map(model => ({
      id: `model_${snapshotId}_${hashToId(model.id)}`,
      snapshotId,
      provider: 'openrouter',
      modelId: model.id,
      canonicalSlug: model.canonicalSlug,
      displayName: model.displayName,
      contextLength: model.contextLength,
      promptUsdPerToken: String(model.promptUsdPerToken),
      completionUsdPerToken: String(model.completionUsdPerToken),
      inputCacheReadUsdPerToken:
        model.inputCacheReadUsdPerToken !== undefined
          ? String(model.inputCacheReadUsdPerToken)
          : null,
      inputCacheWriteUsdPerToken:
        model.inputCacheWriteUsdPerToken !== undefined
          ? String(model.inputCacheWriteUsdPerToken)
          : null,
      createdAt: now,
    })),
  )

  return {
    snapshot: {
      id: snapshotId,
      provider: 'openrouter',
      sourceUrl,
      sourceHash,
      modelCount: catalog.models.length,
      fetchedAt,
      rawCatalogStorageKey,
      createdAt: now.toISOString(),
    },
    models: catalog.models,
  }
}

export const getCurrentOpenRouterCatalogSnapshot = async (
  runtime: ApiRuntime,
): Promise<PersistedCatalogResult | null> => {
  const db = getD1Database(runtime)

  const snapshots = await db
    .select()
    .from(modelCatalogSnapshots)
    .where(eq(modelCatalogSnapshots.provider, 'openrouter'))
    .orderBy(desc(modelCatalogSnapshots.fetchedAt))
    .limit(1)

  const snapshot = snapshots[0]
  if (!snapshot) return null

  const models = await db
    .select()
    .from(modelCatalogEntries)
    .where(eq(modelCatalogEntries.snapshotId, snapshot.id))

  return {
    snapshot: toSnapshotResponse(snapshot),
    models: models.map(toCatalogModelResponse),
  }
}

const getD1Database = (runtime: ApiRuntime) => {
  if (!runtime.bindings.DB) {
    throw new Error('D1 binding is not configured for the API runtime.')
  }

  return createD1DatabaseAdapter(runtime.bindings.DB as never).db
}

const getR2Storage = (runtime: ApiRuntime) => {
  if (!runtime.bindings.ASSETS) {
    throw new Error('R2 assets binding is not configured for the API runtime.')
  }

  return createR2StorageAdapter(runtime.bindings.ASSETS as never)
}

const hashToId = (value: string): string =>
  hashText(value).slice(0, 12)

const hashText = (value: string): string => {
  let hash = 2166136261

  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index)
    hash = Math.imul(hash, 16777619)
  }

  return Math.abs(hash >>> 0).toString(16).padStart(8, '0')
}

const sha256Hex = async (value: string): Promise<string> => {
  const digest = await crypto.subtle.digest(
    'SHA-256',
    new TextEncoder().encode(value),
  )

  return [...new Uint8Array(digest)]
    .map(byte => byte.toString(16).padStart(2, '0'))
    .join('')
}

const toSnapshotResponse = (snapshot: ModelCatalogSnapshotRecord) => ({
  id: snapshot.id,
  provider: snapshot.provider,
  sourceUrl: snapshot.sourceUrl,
  sourceHash: snapshot.sourceHash,
  modelCount: snapshot.modelCount,
  fetchedAt: new Date(snapshot.fetchedAt).toISOString(),
  rawCatalogStorageKey: snapshot.rawCatalogStorageKey,
  createdAt: new Date(snapshot.createdAt).toISOString(),
})

const toCatalogModelResponse = (
  entry: ModelCatalogEntryRecord,
): OpenRouterCatalog['models'][number] => ({
  source: 'openrouter_public_catalog',
  id: entry.modelId,
  canonicalSlug: entry.canonicalSlug ?? undefined,
  displayName: entry.displayName,
  contextLength: entry.contextLength ?? undefined,
  promptUsdPerToken: Number(entry.promptUsdPerToken),
  completionUsdPerToken: Number(entry.completionUsdPerToken),
  inputCacheReadUsdPerToken:
    entry.inputCacheReadUsdPerToken !== null &&
    entry.inputCacheReadUsdPerToken !== undefined
      ? Number(entry.inputCacheReadUsdPerToken)
      : undefined,
  inputCacheWriteUsdPerToken:
    entry.inputCacheWriteUsdPerToken !== null &&
    entry.inputCacheWriteUsdPerToken !== undefined
      ? Number(entry.inputCacheWriteUsdPerToken)
      : undefined,
})

