    const session = await findSessionContaining('"name":"AskUserQuestion"')

    if (!session) {
      return
    }

    const canonical = await parseRealSession(session)

    expect(
      canonical.artifacts.some(
        artifact => artifact.artifactType === 'question_interaction',
      ),
    ).toBe(true)
  })

