    expect(session).toBeTruthy()

    if (!session) return

    const canonical = await parseRealSession(session)
    const metrics = (canonical.providerData?.claudeCode as {
      metrics?: {
        messageCount: number
        turnCount: number
        modelsUsed: string[]
        inputTokens: number
        outputTokens: number
        durationMs?: number
      }
