import { type ApiRuntimeInput, type ApiWorkerBindings, extractStringRuntimeEnv } from './bindings'
import { createApiEnv } from './env'

export const createApiRuntime = (input: ApiRuntimeInput) => ({
  env: createApiEnv(extractStringRuntimeEnv(input)),
  bindings: {
    DB: input.DB,
    ASSETS: input.ASSETS,
    INGEST_QUEUE: input.INGEST_QUEUE,
  } satisfies ApiWorkerBindings,
})

export type ApiRuntime = ReturnType<typeof createApiRuntime>

import { OpenAPIHono } from '@hono/zod-openapi'
import { createD1DatabaseAdapter } from '@howicc/db/adapters/d1'
import { createHowiccAuth } from '@howicc/auth/server'
import { cors } from 'hono/cors'

const app = new OpenAPIHono()

type ViewerRouteEnv = {
  WEB_APP_URL: string
  API_BASE_URL: string
  BETTER_AUTH_SECRET?: string
  GITHUB_CLIENT_ID?: string
  GITHUB_CLIENT_SECRET?: string
  DB: unknown
}

const getAuth = (runtimeEnv: ViewerRouteEnv) =>
  createHowiccAuth({
    db: createD1DatabaseAdapter(runtimeEnv.DB as never).db,
    baseURL: runtimeEnv.API_BASE_URL,
    secret:
      runtimeEnv.BETTER_AUTH_SECRET ?? 'dev-better-auth-secret-change-me-please',
    webOrigin: runtimeEnv.WEB_APP_URL,
    githubClientId: runtimeEnv.GITHUB_CLIENT_ID,
    githubClientSecret: runtimeEnv.GITHUB_CLIENT_SECRET,
  })

app.use('/viewer/*', async (c, next) => {
  const runtimeEnv = c.env as ViewerRouteEnv

  return cors({
    origin: runtimeEnv.WEB_APP_URL,
    allowHeaders: ['Content-Type', 'Authorization'],
    allowMethods: ['GET', 'OPTIONS'],
    exposeHeaders: ['Content-Length'],
    maxAge: 600,
    credentials: true,
  })(c, next)
})

app.get('/viewer/session', async c => {
  const runtimeEnv = c.env as ViewerRouteEnv
  const auth = getAuth(runtimeEnv)
  const session = await auth.api.getSession({ headers: c.req.raw.headers })

  return c.json(session, session ? 200 : 200)
})

app.get('/viewer/protected', async c => {
  const runtimeEnv = c.env as ViewerRouteEnv
  const auth = getAuth(runtimeEnv)
  const session = await auth.api.getSession({ headers: c.req.raw.headers })

  if (!session) {
    return c.html(
      `
        <h2>Access denied</h2>
        <p>You need to be signed in to see this content.</p>
      `,
      401,
    )
  }

  return c.html(`
    <h2 style="margin: 0 0 0.75rem;">Protected Content - You're In!</h2>
    <p>Welcome to the protected area.</p>
    <p><strong>User ID:</strong> ${session.user.id}</p>
    <p><strong>Session ID:</strong> ${session.session.id}</p>
    <p><strong>Email:</strong> ${session.user.email}</p>
  `)
})

export default app

