import { OpenAPIHono } from '@hono/zod-openapi'
import { createD1DatabaseAdapter } from '@howicc/db/adapters/d1'
import { createHowiccAuth } from '@howicc/auth/server'
import { cors } from 'hono/cors'
import {
  getOrComputeUserProfile,
  recomputeUserProfile,
  getDigestCount,
} from '../modules/profile/service'
import { createApiRuntime } from '../runtime'

const app = new OpenAPIHono()

type ProfileRouteEnv = {
  WEB_APP_URL: string
  API_BASE_URL: string
  BETTER_AUTH_SECRET?: string
  GITHUB_CLIENT_ID?: string
  GITHUB_CLIENT_SECRET?: string
  DB: unknown
  ASSETS?: unknown
  INGEST_QUEUE?: unknown
}

const getAuth = (runtimeEnv: ProfileRouteEnv) =>
  createHowiccAuth({
    db: createD1DatabaseAdapter(runtimeEnv.DB as never).db,
    baseURL: runtimeEnv.API_BASE_URL,
    secret:
      runtimeEnv.BETTER_AUTH_SECRET ?? 'dev-better-auth-secret-change-me-please',
    webOrigin: runtimeEnv.WEB_APP_URL,
    githubClientId: runtimeEnv.GITHUB_CLIENT_ID,
    githubClientSecret: runtimeEnv.GITHUB_CLIENT_SECRET,
  })

const getRuntime = (env: ProfileRouteEnv) =>
  createApiRuntime(env as never)

const requireAuth = async (c: { env: ProfileRouteEnv; req: { raw: Request } }) => {
  const auth = getAuth(c.env)
  const session = await auth.api.getSession({ headers: c.req.raw.headers })
  return session
}

app.use('/profile/*', async (c, next) => {
  const runtimeEnv = c.env as ProfileRouteEnv

  return cors({
    origin: runtimeEnv.WEB_APP_URL,
    allowHeaders: ['Content-Type', 'Authorization'],
    allowMethods: ['GET', 'POST', 'OPTIONS'],
    exposeHeaders: ['Content-Length'],
    maxAge: 600,
    credentials: true,
  })(c, next)
})

// GET /profile — returns authenticated user's profile
app.get('/profile', async c => {
  const runtimeEnv = c.env as ProfileRouteEnv
  const session = await requireAuth(c)

  if (!session) {
    return c.json({ error: 'Authentication required' }, 401)
  }

  const runtime = getRuntime(runtimeEnv)
  const digestCount = await getDigestCount(runtime, session.user.id)

  if (digestCount === 0) {
    return c.json({
      profile: null,
      digestCount: 0,
      message: 'No sessions synced yet. Use the CLI to sync your Claude Code sessions.',
    })
  }

  const profile = await getOrComputeUserProfile(runtime, session.user.id)

  return c.json({
    profile,
    digestCount,
  })
})

// POST /profile/recompute — force recompute profile
app.post('/profile/recompute', async c => {
  const runtimeEnv = c.env as ProfileRouteEnv
  const session = await requireAuth(c)

  if (!session) {
    return c.json({ error: 'Authentication required' }, 401)
  }

  const runtime = getRuntime(runtimeEnv)
  const profile = await recomputeUserProfile(runtime, session.user.id)

  return c.json({
    profile,
    recomputed: true,
  })
})

export default app

