    expect(d.toolCategories.read).toBeGreaterThan(0)
    expect(d.toolCategories.search).toBeGreaterThan(0)
    expect(d.toolCategories.agent).toBeGreaterThan(0)
    expect(d.toolCategories.write).toBeGreaterThan(0)
