      const session = sessions.find(s => s.sessionId === TARGET_SESSION_ID)!
      canonical = await parseRealSession(session)
    }
    return canonical
  }

  // -- Token deduplication --------------------------------------------------

  it('does not overcount tokens from multi-block API responses', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    // The raw JSONL has 97 assistant entries, many sharing usage snapshots.
    // Naive sum: ~33K input. Deduplicated: ~23K input (30% reduction).
    // The reduction is real but not dramatic because many entries ARE separate
    // API responses (rapid tool call → result → next call cycles).
    expect(metrics.inputTokens).toBeLessThan(30_000)
    expect(metrics.inputTokens).toBeGreaterThan(5_000)

    // Cache write tokens should be reasonable (grows as session grows)
    expect(metrics.cacheCreationInputTokens).toBeGreaterThan(100_000)

    // Output tokens should be present
    expect(metrics.outputTokens).toBeGreaterThan(10_000)

    // Verify dedup actually reduces vs naive sum: the timeline should have
    // fewer entries than total messages (which includes all raw entries)
    expect(metrics.usageTimeline.length).toBeLessThan(metrics.messageCount)
  })

  it('produces fewer usage timeline entries than raw assistant JSONL entries', async () => {
    const session = await getCanonical()
    const metrics = getMetrics(session)

    // The usage timeline should have fewer entries than raw assistant JSONL
    // entries because dedup collapses multi-block API responses.
    // This is a living session so absolute numbers will grow, but the ratio
    // should stay consistent: timeline entries < total assistant messages.
    expect(metrics.usageTimeline.length).toBeLessThan(metrics.messageCount)
    expect(metrics.usageTimeline.length).toBeGreaterThan(20)
  })

