    const session = await getCanonical()

    const assistantMessages = session.events.filter(e => e.type === 'assistant_message')

    for (const msg of assistantMessages) {
      if (msg.type !== 'assistant_message') continue
      // A leaked thinking block would start with {"type":"thinking" — that's
      // the signature of a block that wasn't filtered. Conversational text that
      // happens to mention thinking blocks (like this session does) won't start
      // with that JSON prefix.
      expect(msg.text).not.toMatch(/^\{"type":"thinking"/)
    }
  })

  it('produces assistant messages without raw JSON thinking artifacts', async () => {
    const session = await getCanonical()

    // Redacted thinking blocks (empty text + signature) should be dropped.
