const buildSystemEvent = (entry: ParsedRawEntry): CanonicalEvent | undefined => {
  const subtype = getString(entry.raw.subtype)
  const timestamp = getEntryTimestamp(entry) ?? new Date(0).toISOString()

  if (subtype === 'stop_hook_summary') {
    const hookInfos = Array.isArray(entry.raw.hookInfos) ? entry.raw.hookInfos : []

    const hookEvent: HookEvent = {
      type: 'hook',
      id: `${entry.index}:system:stop_hook_summary`,
      timestamp,
      hookEvent: 'stop',
      toolUseId: getString(entry.raw.toolUseID),
      label: 'stop_hook_summary',
      text: hookInfos
        .map(hookInfo =>
          isRecord(hookInfo)
            ? `${getString(hookInfo.command) ?? 'unknown'} (${getString(hookInfo.durationMs) ?? hookInfo.durationMs ?? 'n/a'}ms)`
            : undefined,
        )
        .filter((value): value is string => Boolean(value))
        .join('\n'),
      preventedContinuation:
        typeof entry.raw.preventedContinuation === 'boolean'
          ? entry.raw.preventedContinuation
          : false,
    }

    return hookEvent
  }

  const notice: SystemNoticeEvent = {
    type: 'system_notice',
    id: `${entry.index}:system:${subtype ?? 'unknown'}`,
    timestamp,
    subtype: subtype ?? 'unknown',
    level: getString(entry.raw.level) as SystemNoticeEvent['level'] | undefined,
    text:
      extractTextContent(entry.raw.message) ??
      getString(entry.raw.stopReason) ??
      subtype ??
      'system notice',
    data: entry.raw,
  }

  return notice
}

const getToolResultStatus = (
  block: Record<string, unknown>,
  topLevelResult: unknown,
): ToolResultEvent['status'] => {
  if (block.is_error === true) {
    return 'error'
  }

  if (isRecord(topLevelResult) && topLevelResult.interrupted === true) {
    return 'partial'
  }

  return 'ok'
}

// Derive a human-readable label from tool input when no explicit description exists
const deriveToolLabel = (toolName: string, input: Record<string, unknown>): string | undefined => {
  const explicit = getString(input.description)
  if (explicit) return explicit

  switch (toolName) {
    case 'Read':
      return getString(input.file_path)
    case 'Write':
      return getString(input.file_path)
    case 'Edit':
      return getString(input.file_path)
    case 'Glob':
      return getString(input.pattern)
    case 'Grep':
      return getString(input.pattern)
    case 'Bash': {
      const command = getString(input.command)
      return command ? (command.length > 80 ? `${command.slice(0, 77)}...` : command) : undefined
    }
    case 'Agent':
      return getString(input.prompt)
        ? (getString(input.prompt)!.length > 80 ? `${getString(input.prompt)!.slice(0, 77)}...` : getString(input.prompt))
        : undefined
    default:
      return undefined
  }
}

import type { CanonicalMetadata } from '@howicc/canonical'
import type { DiscoveredSession } from '@howicc/parser-core'
import type { ParsedRawEntry } from '../jsonl'
import { getCwd, getGitBranch, getSlug, getEntryTimestamp } from './raw'
import { getString } from '../utils'

export const buildSessionMetadata = (
  entries: ParsedRawEntry[],
  session: DiscoveredSession,
): CanonicalMetadata => {
  const reversedEntries = [...entries].reverse()

  const customTitle = reversedEntries.find(entry => entry.raw.type === 'custom-title')
  const summary = reversedEntries.find(entry => entry.raw.type === 'summary')
  const tag = reversedEntries.find(entry => entry.raw.type === 'tag')
  const mode = reversedEntries.find(entry => entry.raw.type === 'mode')

  const timestamps = entries
    .map(getEntryTimestamp)
    .filter((timestamp): timestamp is string => Boolean(timestamp))
    .sort()

  const latestEntry = reversedEntries.find(
    entry => getCwd(entry) || getGitBranch(entry) || getSlug(entry),
  )

  return {
    title: undefined,
    customTitle: customTitle ? getString(customTitle.raw.customTitle) : undefined,
    summary: summary ? getString(summary.raw.summary) : undefined,
    tag: tag ? getString(tag.raw.tag) : undefined,
    cwd: latestEntry ? getCwd(latestEntry) : session.projectPath,
    gitBranch: latestEntry ? getGitBranch(latestEntry) : session.gitBranch,
    createdAt: timestamps[0] ?? session.createdAt ?? session.updatedAt,
    updatedAt:
      timestamps[timestamps.length - 1] ?? session.updatedAt ?? session.createdAt,
    mode: mode ? getString(mode.raw.mode) : undefined,
  }
}

